    if start not in graph or end not in graph:
        return None
    visited = set()
    queue = [(start, [start])]
    while queue:
        current, path = queue.pop(0)
        if current == end:
            return path
        if current not in visited:
            visited.add(current)
            for neighbor, weight in graph[current].items():
                if neighbor not in visited:
                    queue.append((neighbor, path + [neighbor]))
